const items = $input.all();

function stripHtml(value) {
  return String(value ?? "")
    .replace(/<script[\s\S]*?<\/script>/gi, "")
    .replace(/<style[\s\S]*?<\/style>/gi, "")
    .replace(/<[^>]+>/g, " ")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&#40;/g, "(")
    .replace(/&#41;/g, ")")
    .replace(/&#39;/g, "'")
    .replace(/&quot;/g, '"')
    .replace(/\s+/g, " ")
    .trim();
}

return items.map((item) => {
  const rawHtml =
    item.json.detailHtml ??
    item.json.data ??
    item.json.body ??
    item.json.html ??
    "";

  const detailText = stripHtml(rawHtml).slice(0, 6000);

  return {
    json: {
      title: item.json.title ?? "제목 없음",
      url: item.json.url ?? "",
      detailText,
    },
  };
});

const items = $input.all();

function extractText(value) {
  if (value === null || value === undefined) return "";

  if (typeof value === "string") {
    return value;
  }

  if (typeof value === "number" || typeof value === "boolean") {
    return String(value);
  }

  if (Array.isArray(value)) {
    return value.map(extractText).filter(Boolean).join("\n");
  }

  if (typeof value === "object") {
    const preferredKeys = [
      "text",
      "content",
      "output_text",
      "message",
      "output",
      "response",
      "result",
      "data",
    ];

    for (const key of preferredKeys) {
      if (value[key] !== undefined) {
        const extracted = extractText(value[key]);
        if (extracted) return extracted;
      }
    }

    return JSON.stringify(value, null, 2);
  }

  return String(value);
}

const lines = ["*잡코리아 AI 요약 채용공고*"];

for (const item of items) {
  const summary = extractText(item.json);

  lines.push(summary.slice(0, 2500));
}

return [
  {
    json: {
      response_type: "ephemeral",
      text: lines.join("\n\n---\n\n").slice(0, 3000),
    },
  },
];

const body = $json.body ?? $json;

return [
  {
    json: {
      slackResponseUrl: body.response_url,
      command: body.command ?? "/jobs",
      text: body.text ?? "",
      userId: body.user_id ?? "",
    },
  },
];
